"use strict";let lastUsername=null;document.addEventListener("contextmenu",e=>{const t=e.target;if(!(t instanceof HTMLImageElement))return;const n=t.closest('article[data-testid="tweet"]');if(!n)return void(lastUsername=null);const s=n.querySelectorAll('a[href^="/"]');for(const e of s){const t=e.getAttribute("href")?.match(/^\/([A-Za-z0-9_]+)$/);if(t)return void(lastUsername=t[1])}lastUsername=null}),chrome.runtime.onMessage.addListener((e,t,n)=>{"GET_USERNAME"===e.type&&n({username:lastUsername})});